previewCss:
.darma-loader-darma-custom-421 {color: var(--loader-color, #0891b2);
  --loader-secondary-color: var(--loader-secondary-color, #22d3ee);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 60px;
  height: 25px;
  border: 2px solid;
  box-sizing: border-box;
  border-radius: 50%;
  display: grid;
  animation: darma-loader-darma-custom-421-l2 2s infinite linear;
}.darma-loader-darma-custom-421:before,.darma-loader-darma-custom-421:after {content: "";
  grid-area: 1/1;
  border: inherit;
  border-radius: 50%;
  animation: inherit;
  animation-duration: 3s;
}.darma-loader-darma-custom-421:before {--s:-1;
}@keyframes darma-loader-darma-custom-421-l2 {100% {transform: scale(calc(var(--s,1)*1turn))}}

